function LBattleViewUnit:PlayIdle()
    if not self._spineDp or IsNull(self._spineDp:GetDpGo()) then
        return
    end
    if not self._isEnableAni then
        self:PlayAniActor('stop', false)
        return
    end

    if self._modelAniMap['idle'] then
        self:PlayAniActor('idle', true)
    else
        self:PlayAniActor('idle1', true)
    end
end

