---@param unitData LxUnitPosObj
function LBattleViewUnit:InitData(unitData)
    if unitData then
        self.id = tostring(unitData.id)
        self.index = unitData.index
        self.unitType = unitData.unitType
        self.skinRefId = unitData.skinRefId or 0
        self.heroRefId = tonumber(unitData.heroRefId or unitData.refId) or 0
        self.modelName = unitData.model
        self.level = unitData.level
    end
    if self.heroRefId == 0 and self.skinRefId == 0 then
        --if self:IsRole() then
        --    local gender = self._gender or 0
        --    ---@type LxRoleInfo
        --    local roleInfo = ModuleCenter.Role:GetRoleInfo()
        --    if roleInfo then
        --        gender = roleInfo.gender
        --    end
        --    local genderRef = GameTable.RoleGenderRef[gender]
        --    if genderRef then
        --        self.heroRefId = tonumber(genderRef.model)
        --    end
        --end
    end
    if self:IsMonster() then
        local monsterAttrRef = GameTable.MonsterAttrRef[self.heroRefId]
        if monsterAttrRef then
            self.level = monsterAttrRef.lv
            local scale = monsterAttrRef.scale
            self._baseScale = scale
            self.skinRefId = monsterAttrRef.effectId
            if self.skinRefId == 0 then
                self.skinRefId = monsterAttrRef.heroId
            end
            self:UpdateSpineScale()
        end
    end

    if unitData.state == BattleUnitState.Dead then
        self._state = BattleUnitState.Dead
        self._bDeaded = true
        self._bDeadEnd = true
    end
    if self._unitRootTrans then
        self:SetLocalTmpPosValue(self._gridPos)
        self._unitRootTrans.localPosition = self._localTmpPosition
        if self._state == BattleUnitState.Dead then
            if IsValid(self._unitRootGo) then
                ShowObject(self._unitRootGo, false)
            end
        end
    end

    self:SetRenderOrder(self:GetRenderOrder())
end

function LBattleViewUnit:IsMonster()
