function LBattleViewUnit:SetUnitView(rootNode, teamIdx, unitData)
    self:SetTeamIdx(teamIdx)
    self._parentRoot = rootNode
    self._orgPos = Vector3.zero

    if not self._unitRootTrans then
        self._randZ = math.random(100, 999) * 0.0000001
        self._unitRootGo = LxResUtil.NewGameObject("unit")
        self._unitRootTrans = self._unitRootGo.transform
        self._unitRootTrans:SetParent(self._parentRoot, false)
        ResetTransDefault(self._unitRootTrans)
        self:InitObjectCtrl(self._unitRootGo)
    end

    if unitData then
        self:InitData(unitData)
    end

    self:SetDebugName()
end

function LBattleViewUnit:SetTeamIdx(teamIdx)
    self.teamIdx = teamIdx or 1
    if self.teamIdx == BattleTeamSide.teamA then
        self._direction = LFightConst.DIRECTION_RIGHT
    else
        self._direction = LFightConst.DIRECTION_LEFT
    end
end

function LBattleViewUnit:SetStandRoot(standRoot)
    self._standRoot = standRoot
end

function LBattleViewUnit:ResetUnitRoot()
    if not IsNull(self._unitRootTrans) then
        self._unitRootTrans:SetParent(self._parentRoot)
        self:SetLocalTmpPosValue(self._gridPos)
        self._unitRootTrans.localPosition = self._localTmpPosition
    end
end

function LBattleViewUnit:ShowStandQuality(bShow)
    if not bShow then
        local stand = self._standRoot:Find("Stand")
        if stand then
            ShowObject(stand.gameObject, false)
        end
        local BattleState = self._standRoot:Find("BattleState")
        if BattleState then
            ShowObject(BattleState.gameObject, true)
        end
        return
    end
    local refId = tonumber(self.heroRefId)
    local skinRefId = tonumber(self.skinRefId or "0")
    if skinRefId > 0 then
        refId = skinRefId
    end
    local heroRef = GameTable.CharacterRef[refId]
    --- 设置站位品质
    if self._standRoot then
        local stand = self._standRoot:Find("Stand")
        if stand and heroRef then
            ShowObject(stand.gameObject, true)
            local qualityRoot = stand:Find("Quality")
            ShowObject(qualityRoot.gameObject, true)
            ShowAllChild(qualityRoot.gameObject, false)
            local qualityStand = qualityRoot:Find("Quality"..heroRef.quality)
            if qualityStand then
                ShowObject(qualityStand.gameObject, true)
            end
        end
        local BattleState = self._standRoot:Find("BattleState")
        if BattleState then
            ShowObject(BattleState.gameObject, true)
        end
    end
end

function LBattleViewUnit:GetModelEulerAngles()
    if self._spineDp then
