function LBattleViewUnit:InnerLoadUnitView()
    self:SetLocalTmpPosValue(self._gridPos)
    self._unitRootTrans.localPosition = self._localTmpPosition

    local modelName = ""
    if self.isSkillEditor then
        modelName = self.modelName
    else
        local refId = tonumber(self.heroRefId)
        local skinRefId = tonumber(self.skinRefId or "0")
        if skinRefId > 0 then
            refId = skinRefId
        end
        local heroEffectRef = GameTable.CharacterEffectRef[refId]
        if not heroEffectRef then
            self:OnLoadModel(nil)
            return
        end
        modelName = heroEffectRef.model
        self.modelName = modelName
    end
    if self._spineDp then
        self._spineDp:Dispose()
    end

    local offsetX, offsetY = LxDataHelper.GetSpineOffset(modelName, 0, BattleHudHeight)
    self._hudOffset.x = offsetX
    self._hudOffset.y = offsetY

    self._spineDp = require("LApp.component.dp.LxSpineDp"):new()
    self._spineDp:InitDp(modelName, self._unitRootTrans)
    self._spineDp:SetFormationState(true)
    self._spineDp:SetLocalPosition(Vector3.zero)
    self._spineDp:SetScale(self._modelScale)
    self._spineDp:SetFlipX(self.teamIdx == BattleTeamSide.teamB)
    self._spineDp:SetLoadedCallback(function(modelDp)
        self:OnLoadModel(modelDp)
    end)
    self._spineDp:SetLoadFailCallback(function(modelDp)
        self:OnLoadModel(modelDp)
    end)
    self._spineDp:Load()
end

function LBattleViewUnit:InitObjectCtrl(dpGo)
    if dpGo and IsValid(dpGo) then
        local comp = dpGo:GetComponent(typeofObjectCtrl2D)
        if not comp then
            comp = dpGo:AddComponent(typeofObjectCtrl2D)
        end
        comp.randZ = self._randZ
        comp.zType = 1
        self._objectCtrl2D = comp
    end
end

function LBattleViewUnit:GetObjectCtrl2D()
    return self._objectCtrl2D
end

function LBattleViewUnit:GetTime()
    return self._viewMgr:GetTime()
end

