function LBattleViewUnit:Create(heroData, parentTrans, gridPos, completeFunc)
    self._rootTrans = parentTrans
    self.unitData = heroData
    self._gridPos = gridPos

    self._completeFunc = completeFunc

    self._randZ = math.random(100, 999) * 0.0000001

    local actOn = heroData:GetTeamType()
    if actOn == BattleTeamSide.teamA then
        self._direction = LFightConst.DIRECTION_RIGHT
        self.teamIdx = BattleTeamSide.teamA
    else
        self._direction = LFightConst.DIRECTION_LEFT
        self.teamIdx = BattleTeamSide.teamB
    end

    if not self:InitData() then
        return false
    end

    if self:IsOnGridObj() then
        self:InitAllEffectData()
        self:InitActor()
        self:InitDisplay()
    end

    self:InitObjHud()

    self:SetHeroBgPos()

    return true
end

---初始化当前显示对象数据
function LBattleViewUnit:InitCfgShowEffectList()
    local heroData = self.unitData
    if not self:IsOnGridObj() then return end
    self._objName = heroData:GetName()
    self._showEffRefList = {}
    for k,v in ipairs(heroData.effectIdList) do
        local ref = GameTable.CharacterEffectRef[v]
        self._showEffRefList[k] = ref
    end
end

function LBattleViewUnit:InitAllEffectData()
    if not self.unitData then
        return
    end

    local buffList = self.unitData:GetBuffList()
    for i, buff in ipairs(buffList) do
        local buffs = {}
        buffs.buffUniqueId = buff.buffUniqueId
        buffs.buffId = buff.buffId
        buffs.round = buff.round
        buffs.startRound = buff.startRound
        buffs.currentRound = buff.currentRound
        table.insert(self._buffList, buffs)
    end

    for k,v in pairs(self.unitData.blockList) do
        local block = table.clone(v)
        table.insert(self._blockList,block)
    end

    for k,v in pairs(self.unitData.shieldList) do
        local shield = table.clone(v)
        self._shieldList[shield.shieldUniqueId] = shield
    end

    for k,v in pairs(self.unitData.angerList) do
        local anger = table.clone(v)
        self._angerList[anger.buffUniqueId] = anger
    end

    self._canRelive = self.unitData.canRelive

end

