function LBattleViewUnit:InitDataOld()
    local heroData = self.unitData

    self.index = heroData:GetIndex()
    self.id = heroData:GetId()

    local isMonster = heroData:IsMonster()

    local aniShowEffRef = nil
    local objName = nil

    self._battleObjType = heroData:GetBattleObjType()

    local refId = heroData:GetRefId()
    if self:IsOnGridObj() then

        -- 【C宠物系统】删掉宠物系统相关
        -- if self._battleObjType == LFightConst.OBJ_PET then
        -- 	local star = heroData:GetStar()
        -- 	local starRef = gModelPetSpace:GetPetStarRef(refId,star)
        -- 	local effectId = starRef.effectId
        -- 	aniShowEffRef = gModelPetSpace:GetPetShowRef(effectId)
        -- 	objName = I18nText(aniShowEffRef.name)
        -- else
        if isMonster then
            local monRef = GameTable.MonsterAttrRef[refId]
            if not monRef then
                printInfoN("怪物不存在 refId" .. tostring(refId))
                return false
            end

            local effectId = heroData:GetShowEffId() --monRef.effectId
            aniShowEffRef = GameTable.CharacterEffectRef[effectId]
            if not aniShowEffRef then
                printInfoN(string.format("表现数据不存在怪物refID为%s,表现refId为%s" ,tostring(refId),tostring(effectId)))
                return false
            end
            objName = I18nText(monRef.name)
            if string.isempty(objName) then
                objName = I18nText(aniShowEffRef.name)
            end

            -- 获取怪物的缩放
            self._scale = tonumber(monRef.scale)
        else
            local skinId = heroData:GetSkinId()
            local heroEffectId
            if skinId and skinId>0 then --英雄皮肤
                heroEffectId = skinId
            else
                local heroRef = gModelHero:GetHeroRef(refId)
                if not heroRef then
                    printInfoN("英雄不存在 refId" .. tostring(refId))
                    return false
                end

                local form = heroData:GetForm()
                local star = heroData:GetStar()
                local starRef = gModelHero:GetHeroStarRef(refId,form,star)
                heroEffectId = starRef.effectId
            end

            aniShowEffRef = GameTable.CharacterEffectRef[heroEffectId]
            if not aniShowEffRef then
                printInfoN(string.format("表现数据不存在英雄refID为%s,表现refId为%s" ,tostring(refId),tostring(heroEffectId)))
                return false
            end
            objName = I18nText(aniShowEffRef.name)
        end

        -- end


        self._curHp = heroData:GetHp()
        self._maxHP = heroData:GetMaxHp()
        self._refId = refId

        local showEffRefList = {}
        table.insert(showEffRefList,aniShowEffRef)
        local effectIdTwo = aniShowEffRef.skinState2
        if effectIdTwo and effectIdTwo > 0 then
            local temp = GameTable.CharacterEffectRef[effectIdTwo]
            table.insert(showEffRefList,temp)
        end

        self._objName = objName
        self._showEffRefList = showEffRefList
        -- self._sCardData = heroData:GetSCardData()

    end

    return true
end

