---@return V_HeroEffectRef
function LBattleViewUnit:GetShowEffRef()
    local cnt = #self._showEffRefList
    local index = math.min(cnt ,self._showEffIndex)
    local showEffRef = self._showEffRefList[index]
    return showEffRef
end

function LBattleViewUnit:GetDeadInterval()
    local showEffRef = self:GetShowEffRef()
    return LxDataHelper.GetSpineAniTime(showEffRef.prefabName, LSpineAniConst.die, 0)
end

---@return LxSpineDp
function LBattleViewUnit:GetDisplayObj()
    local cnt = self._spineCount
    local index = math.min(cnt ,self._showEffIndex)
    if index == 1 then
        return self._spineDp
    elseif index  == 2 then
        return self._spineDp1
    elseif index == 3 then
        return self._spineDp2
    end
end

--- 如果又变身的话，使用变身后的
function LBattleViewUnit:GetTransformDisplayObj()
    if self._newChangeIndex and self._newChangeIndex > 0 then
        local cnt = self._spineCount
        local index = math.min(cnt ,self._newChangeIndex)
        if index == 1 then
            return self._spineDp
        elseif index  == 2 then
            return self._spineDp1
        elseif index == 3 then
            return self._spineDp2
        end
    end
    return self:GetDisplayObj()
end

function LBattleViewUnit:ChangeShowEffIndex(showEffIndex)
    if self._showEffIndex == showEffIndex then
        return
    end
    self._showEffIndex = showEffIndex

    if not self._isChangeSpine then
        self:RefreshHeroShowEff()
    end
end

function LBattleViewUnit:RefreshHeroShowEff()
    local showEffIndex = self._showEffIndex

    local cnt = #self._spineCount
    showEffIndex = math.min(showEffIndex,cnt)

    if self._spineDp then
        self._spineDp:SetVisible(showEffIndex == 1)
    end

    if self._spineDp1 then
        self._spineDp1:SetVisible(showEffIndex == 1)
    end

    if self._spineDp2 then
        self._spineDp2:SetVisible(showEffIndex == 1)
    end
end

-----------------------------------------------------------------
function LBattleViewUnit:ChangeDirToPos(tarPos)
    local dir = self._direction
    local pos = self:GetPosition()
    if pos.x < tarPos.x then
        dir = LFightConst.DIRECTION_RIGHT
    elseif pos.x > tarPos.x then
        dir = LFightConst.DIRECTION_LEFT
    end
    if dir ~= self._direction then
        self:SetDirection(dir)
    end
end

---@param dp LxSpineDp
function LBattleViewUnit:_SetDpDirection(dp, needFlip)
    dp:SetFlipX(needFlip)
    if needFlip then
        local topNode,defaultPos = dp:GetTopNodeInfo()
        local pos = Vector3.New(-defaultPos.x,defaultPos.y,0)
        topNode.localPosition = pos
    end
end

function LBattleViewUnit:SetDirection(dir)
    self._direction = dir

    local needFlip = dir == LFightConst.DIRECTION_LEFT and not self._useRightSpine

    if self._spineDp then
        self:_SetDpDirection(self._spineDp, needFlip)
    end

    if self._spineDp1 then
        self:_SetDpDirection(self._spineDp1, needFlip)
    end

    if self._spineDp2 then
        self:_SetDpDirection(self._spineDp2, needFlip)
    end
end

function LBattleViewUnit:GetDirection()
    return self._direction
end

function LBattleViewUnit:SetRenderOrder(order)
    if self._spineDp then
        self._spineDp:SetRenderOrder(order)
    end

    if self._spineDp1 then
        self._spineDp1:SetRenderOrder(order)
    end
    if self._spineDp2 then
        self._spineDp2:SetRenderOrder(order)
    end

    for k,v in pairs(self._curBuffEffectList) do
        v:ResetOrder(order)
    end

    self:RefreshBuffActLayer(order)
end

function LBattleViewUnit:GetRenderOrder()
    local index = self.index or 1
    local order = LBattleIndexToOrder.IndexToOrder[index]

    return order
end

function LBattleViewUnit:GetRenderLayer()
    if self._isUpperLayer then
        return "ObjectUp"
    else
        return "Object"
    end
end

function LBattleViewUnit:SetPosition(pos)
    --为了避免pos被污染
    self:SetLocalTmpPosValue(pos)
    if IsValid(self._unitRootTrans) then
        self._unitRootTrans.localPosition = self._localTmpPosition
    end
    self:StopMove()
end

function LBattleViewUnit:SetLocalTmpPosValue(pos)
    self._localTmpPosition.x = pos.x
    self._localTmpPosition.y = pos.y
    self._localTmpPosition.z = pos.y * 0.01 + self._randZ
end


function LBattleViewUnit:GetPosition()
    if self._unitRootTrans then
        local pos = self._unitRootTrans.localPosition
        self._localTmpPosition.x = pos.x
        self._localTmpPosition.y = pos.y
        self._localTmpPosition.z = pos.z
    end
    return self._localTmpPosition
end

function LBattleViewUnit:GetGridPos()
    return self._gridPos
end

function LBattleViewUnit:GetHudPos()
    local x = self._gridPos.x + self._hudOffset.x
    local y = self._gridPos.y + self._hudOffset.y
    local z = self._gridPos.z
    return Vector3(x, y, z)
end

function LBattleViewUnit:SetFormationMode(isFormationMode)
    self.isFormationMode = isFormationMode
end

function LBattleViewUnit:SetGridPos(pos)
    self._gridPos.x = pos.x
    self._gridPos.y = pos.y
    self._gridPos.z = pos.z
end


