function LBattleViewUnit:OnRun(time)
    if self._battleObjType == LFightConst.OBJ_TREASURE then
        self._objHud:OnRun(time)
    elseif self:IsOnGridObj() then
        self._moveActor:OnRun(time)
        self._aniActor:OnRun(time)
        self._objHud:OnRun(time)

        self:UpdateBloodInternal(time)
        self:UpdateDeadState(time)

        if self._bubbleStick then
            self._bubbleStick:OnRun(time)
        end

        self:OnMoveUpdate()
    end
    return true
end

