function LBattleViewUnit:InitBattleStateBgNode()
    local formationData = self._viewMgr:GetViewFace():GetFormationData(self.teamIdx)
    ---@type V_ViewFace_FormationData
    local pointData = formationData[self.index]

    self._battleStatePointData = pointData
    ShowObject(pointData.hurtObj, false)
    ShowObject(pointData.soldObj, false)
end

--- 处于待机状态（未受击、未出手）
function LBattleViewUnit:SetHeroBg_Normal()
    if self._unitBattleState == 0 then return end
    self._unitBattleState = 0

    local pointData = self._battleStatePointData
    ShowObject(pointData.hurtObj, false)
    ShowObject(pointData.soldObj, false)

end

--- 处于出手的角色（不跟随角色移动）
function LBattleViewUnit:SetHeroBg_Attack()
    if self._unitBattleState == 1 then return end
    self._unitBattleState = 1

    local pointData = self._battleStatePointData
    ShowObject(pointData.hurtObj, false)
    ShowObject(pointData.soldObj, true)
end

--- 处于受击范围的阵位（有角色站）
function LBattleViewUnit:SetHeroBg_Hit()
    if self._unitBattleState == 2 then return end
    self._unitBattleState = 2
    local pointData = self._battleStatePointData
    ShowObject(pointData.hurtObj, true)
    ShowObject(pointData.soldObj, false)
end

function LBattleViewUnit:UpdateHeroBgLocalPosition()
    if not self._unitRootTrans then return end
    if not self._rootTrans then return end
    if not self._heroBgTrans then return end
    self._heroBgTrans.localPosition = self._unitRootTrans.localPosition
end

function LBattleViewUnit:InitDisplay()
    local name = string.format("hero_%s_%s",self.teamIdx,self.index)
    local objRoot = CS.NewObject(name,self._rootTrans)
    self:CreateBg(objRoot)
    self._unitRootTrans = objRoot
    local displayObjList = {}
    local isRight = self.teamIdx == BattleTeamSide.teamB
    local useRightSpine = false

    local changeStatus = self.unitData:GetChangeStatus()

    for k,v in ipairs(self._showEffRefList) do
        local spine = v.prefabName
        if isRight and not string.isempty(v.prefabNameRight) then
            spine = v.prefabNameRight
            useRightSpine = true
        end

        if not string.isempty(spine) then
            ---@type LDisplaySpine
            local dp = LDisplaySpine:New()
            table.insert(displayObjList,dp)
            dp:CreateSpine(objRoot, spine)
            dp:SetScale(self._scale)
            dp:SetLoadedFunction(function()
                dp:SetAlpha(0)
                self:OnLoaded(self._isShowDp)
                self:InitEff(dp)
            end)
            dp:SetAnimationCompleteFunc(function(...)
                self:OnAnimationComplete(...)
            end)

            if changeStatus then
                dp:SetChangeStatus(changeStatus)
            end


        end
    end

    self._useRightSpine = useRightSpine

    self._displayObjList = displayObjList

    self:SetLocalTmpPosValue(self._gridPos)

end
function LBattleViewUnit:OnAnimationComplete(animateName)
    if animateName == LSpineAniConst.hit1 then
        self:PlayIdleAni()
    end
end

function LBattleViewUnit:StartLoadDp()
    -- 【G公共支持】删除神器功能相关数据
    -- local objType = self._battleObjType
    -- if objType == LFightConst.OBJ_ARTIFACT then
    -- 	self:PreloadArtifactEff()
    -- 	self:OnBattleObjLoaded()
    if self:IsOnGridObj() then
        self._loadCnt = #self._displayObjList
        for k,v in ipairs(self._displayObjList) do
            v:StartLoad()
        end

        self:LoadBirthEff()
    else
        self:OnBattleObjLoaded()
    end
end

function LBattleViewUnit:OnLoaded(isCreateBlood)

    self._loadCnt = self._loadCnt - 1
    if self._loadCnt > 0 then
        return
    end

    self:RefreshHeroShowEff()

    self:InitBtObjectView()

    self:SetPosition(LFightConst.DEFAULT_LOADED_POS)
    self:SetDirection(self._direction)
    if isCreateBlood then
        self:CreateBloodStick()
    end

    local order = self:GetRenderOrder()
    self:SetRenderOrder(order)

    --出生动画时候才显示
    self:SetObjAlpha(0)

    if self._isUpperLayer then
        self:ToUpperLayer()
    else
        self:ToLowerLayer()
    end

    self:AddClickFun()

    self:CheckLoadEnd()
    --self:OnBattleObjLoaded()
end

function LBattleViewUnit:InitEff(dp)
    if not dp:IsDpValid() then return end
    if not self.unitData then return end

    local heroRefId = self.unitData:GetRefId()
    local star = self.unitData:GetStar()

    local dataMgr = self._viewMgr:GetDataMgr()
    local effName = dataMgr:GetHeroXREffect(heroRefId, star)
    if not effName then return end

    local dpTrans = dp:GetDpTrans()

    local dpEff = require("LApp.component.dp.LxEffectDp"):new()
    dpEff:InitDp(effName, dpTrans)
    table.insert(self._displayObjEffList, dpEff)

    dpEff:SetLoadedCallback(function(dp)
        if not dpEff:IsDpValid() then return end
    end)
    dpEff:Load()
end


function LBattleViewUnit:AddClickFun()

    if not LFightConst.SHOW_ON_INFO[self._battleObjType] then
        return
    end


    --if not self._displayObj then
    --	return
    --end
    --local tran = self._displayObj:GetDpTrans()
    local tran = self._unitRootTrans
    if not IsValid(tran) then
        return
    end

    local spineClick = tran:GetComponent(typeSpineClick)
    if not spineClick then
        spineClick = tran.gameObject:AddComponent(typeSpineClick)
    end
    spineClick.enabled = true
    --self._spineClickCom = spineClick



    spineClick.onClick = function()
        -- 【G公共支持】删除暗黑战争相关数据
        -- if self._isDarkWar then
        -- 	FireEvent(EventNames.DARK_WAR_SHOW_FORMATION,self.id)
        -- else
        FireEvent(EventNames.SHOW_BATTLE_BUFF_WND,self.id)
        -- end
    end
end


