function LBattleViewUnit:ShowBuffInfo()
    if ENABLE_FIGHT_LOG then
        local strList = {}
        for k,v in pairs(self._shieldList) do
            --local buffRef = gModelBattle:GetBuffRef(v.buffId)
            --local universalBuffShow = buffRef.universalBuffShow --1 增益buff 2 减益buff
            local str = string.format("(shield uid %s|bid %s|hp %s)\n",v.shieldUniqueId,v.buffUniqueId,v.curHP)
            table.insert(strList,str)
        end

        for k,v in pairs(self._buffList) do
            local str = string.format("(buff uid %s|refId %s)\n",v.buffUniqueId,v.buffId)
            table.insert(strList,str)
        end

        local content = table.concat(strList)
        if self._bloodStick then
            self._bloodStick:ShowObjInfo(content)

        end
    end
end

