-----------------------------------------------------------------
function LBattleViewUnit:IsCanPlayHit()
    if self:IsDead() then return false end

    local aniName = self._aniActor:GetAniName()
    if not aniName then return true end
    if aniName == LSpineAniConst.idle then
        return true
    end
    local hitAction,_ = self:GetHitActionData()
    if aniName == hitAction then
        return true
    end
    hitAction,_ = self:GetSkillHitActionData()
    if aniName == hitAction then
        return true
    end
    return false
end

function LBattleViewUnit:PlayRunAni(time)
    self:PlayAni(LSpineAniConst.run,true,time)
end

function LBattleViewUnit:PlayIdleAni()
    self:PlayAni(LSpineAniConst.idle,true)
end

function LBattleViewUnit:PlayHitAni()
    local hitAction,hitActionTime = self:GetHitActionData()
    self:PlayAni(hitAction,false,hitActionTime)
end

function LBattleViewUnit:PlaySkillHitAni()
    local hitAction,hitActionTime = self:GetSkillHitActionData()
    self:PlayAni(hitAction,false,hitActionTime)
end

function LBattleViewUnit:PlayHitSound()
    if self:IsDead() then
        local soundName = self:GetDieSound()
        if not string.isempty(soundName) then
            --若有死亡音效，就不播放受击音效
            return
        end
    end

    local soundName = self:GetHitSound()
    if string.isempty(soundName) then return end
    LxUiHelper.PlaySoundByName(soundName)
end

function LBattleViewUnit:PlayDieSound()
    local soundName = self:GetDieSound()
    if string.isempty(soundName) then return end
    LxUiHelper.PlaySoundByName(soundName)
end

function LBattleViewUnit:PlayAnimationInfoEx_Actor(ani, loop, ignoreTimeScale,mixTime,timeScale)
    if self._spineDp then
        self._spineDp:PlayAnimationInfoEx(ani, loop, ignoreTimeScale,mixTime,timeScale)
    end

    if self._spineDp1 then
        self._spineDp1:PlayAnimationInfoEx(ani, loop, ignoreTimeScale,mixTime,timeScale)
    end

    if self._spineDp2 then
        self._spineDp2:PlayAnimationInfoEx(ani, loop, ignoreTimeScale,mixTime,timeScale)
    end
end

function LBattleViewUnit:SetAnimationTimeScale_actor(timeScale)
    if self._spineDp then
        self._spineDp:SetAnimationTimeScale(timeScale)
    end

    if self._spineDp1 then
        self._spineDp1:SetAnimationTimeScale(timeScale)
    end

    if self._spineDp2 then
        self._spineDp2:SetAnimationTimeScale(timeScale)
    end
end

function LBattleViewUnit:PlayAni(animationName,bLoop,time,mixTime)
    self._aniActor:PlayAni(animationName,bLoop,time,mixTime)
end

-- 血条隐藏-显示 动画
function LBattleViewUnit:PlayBlockStickSHTween(time)
    if not self._bloodStick then return end
    if self:IsDead() then return end

    ---# http://192.168.16.2:3002/issues/597
    --- SkillVfxRef中effType=2时，统一做成隐藏自己的血条（包括所有普攻、技能释放动作）

    --self._bloodStick:SetVisible(false)
    self:SetHideBloodKey("blockstick")
    local tweenSeq = self._seqCom:CreateSeq("blockStickTween")
    tweenSeq:AppendInterval(time)
    tweenSeq:OnComplete(function()
        --self._bloodStick:SetVisible(true)
        self:ReleaseHideKey("blockstick")
    end)
    tweenSeq:PlayForward()
end

