function LBattleViewUnit:GetHitActionData()
    local hitAction = LSpineAniConst.hit1
    local showEffect = self:GetShowEffRef()
    local hitTime = LxDataHelper.GetSpineAniTime(showEffect.prefabName, hitAction, 0.2)
    return hitAction,hitTime
end

function LBattleViewUnit:GetSkillHitActionData()
    local hitAction = LSpineAniConst.hit2
    local showEffect = self:GetShowEffRef()
    local hitTime = LxDataHelper.GetSpineAniTime(showEffect.prefabName, hitAction, 0.2)
    return hitAction, hitTime
end

function LBattleViewUnit:GetHitSound()
    local aniShowEfffect = self:GetShowEffRef()
    if aniShowEfffect["soundHit"] ~= nil then
        return aniShowEfffect.soundHit
    end
    return nil
end

function LBattleViewUnit:GetDieSound()
    local aniShowEfffect = self:GetShowEffRef()
    if aniShowEfffect["soundDie"] ~= nil then
        return aniShowEfffect.soundDie
    end
    return nil
end
