function LBattleViewUnit:SynOfflineState(time)
    if self._battleObjType ~= LFightConst.OBJ_NORMAL then
        return
    end
    local heroData = self:GetHeroData()
    local hp = heroData:GetHp()
    self._curHp = hp
    self:UpdateHpProgress(hp)
    local isDead = heroData:IsDead()
    if isDead then
        self:SetObjAlpha(0)
        --self:ShowBloodStick(false)

        self:SetHideBloodKey("dead")
        self:DestroyAllBuff()
        self:ShowDeadBuff()
        self._bDeaded = true
        self._deadActionEnd = true
        self._bDeadEnd = true
        self._state = BattleUnitState.Dead

        self._changeWaitCb = nil
        self._isChangeSpine = false
    end
end
function LBattleViewUnit:UpdateBlood(curHp,playNum,time)
    local maxHp = self._maxHP
    curHp = math.max(0,curHp)
    curHp = math.min(maxHp,curHp)

    self:ClearBloodList()
    self._bloodDataList = self._viewMgr:GetDataMgr():FormatBloodPlayData(self._curHp,curHp,time,playNum)
end

function LBattleViewUnit:ClearBloodList()
    if self._bloodDataList then --立即更新到最新血量
        local last = self._bloodDataList[#self._bloodDataList]
        if last then
            self._curHp = last.curHp
            self:UpdateHpProgress(last.curHp)
            self._viewMgr:RefreshTeamCurHpPercent(self.teamIdx)
        end
        self._bloodDataList =nil

    end
end

function LBattleViewUnit:UpdateBloodInternal(time)
    if not self._bloodDataList then
        return
    end
    local dataList = self._bloodDataList

    local first = dataList[1]
    if not first then
        return
    end

    if first.startTime > time then
        return
    end
    self._curHp = first.curHp
    self:UpdateHpProgress(first.curHp)

    self._viewMgr:RefreshTeamCurHpPercent(self.teamIdx)

    table.remove(self._bloodDataList,1)

end

function LBattleViewUnit:DoBuffUpdate(buff,etype)
    if not buff then return end

    local index = nil
    for i, buffData in ipairs(self._buffList) do
        if buffData.buffUniqueId == buff.buffUniqueId then
            index = i
            break
        end
    end

    local removeBuff
    if etype == LFightConst.BUFF_TYPE_ADD or etype == LFightConst.BUFF_TYPE_UPDATE then
        if index then
            self._buffList[index] = buff
        else
            table.insert(self._buffList,buff)
        end

        if ENABLE_FIGHT_LOG then
            local buffRef = GameTable.CombatBuffRef[buff.buffId]
            local buffName = buffRef and I18nText(buffRef.name) or ""
            self._viewMgr:LogMsg(string.format("hero: %s add or update buff buffId %s uniqueid %s,name %s",tostring(self.id), tostring(buff.buffId), tostring(buff.buffUniqueId) , tostring(buffName)))
        end
    elseif etype == LFightConst.BUFF_TYPE_REMOVE then
        if index then
            local removeEff = table.remove(self._buffList,index)
            removeBuff = {
                buffObj = removeEff,
                buffUniqueId = buff.buffUniqueId
            }

            if ENABLE_FIGHT_LOG then
                local buffRef = GameTable.CombatBuffRef[buff.buffId]
                local buffName = buffRef and I18nText(buffRef.name) or ""
                self._viewMgr:LogMsg(string.format("hero: %s remove buff buffId %s uniqueid %s,name %s",tostring(self.id), tostring(buff.buffId), tostring(buff.buffUniqueId), tostring(buffName)))
            end
        else
            if ENABLE_FIGHT_LOG then
                self._viewMgr:LogMsg(string.format("failed remove buff buffId %s uniqueid %s", tostring(buff.buffId), tostring(buff.buffUniqueId)))
            end
        end
    end
    self._removeBuff = removeBuff

    self._isBuffDirty = true


    self:CheckShowBlood()

    self:RefreshShowEffIndex()
end

function LBattleViewUnit:IsBuffDirty()
    return self._isBuffDirty
end

function LBattleViewUnit:RefreshAfter()
    if not self._isBuffDirty then
        return
    end

    self._isBuffDirty = false

    self:RefreshRelativeData()

    self:RefreshAllBuffEffect()

    self:ShowBuffInfo()

    FireEvent(EventNames.BUFF_DETAILS_UPDATE,self.unitData)
end

function LBattleViewUnit:RefreshRelativeData()
    local buffUIdMap = {}
    for k,v in pairs(self._buffList) do
        buffUIdMap[v.buffUniqueId] = true
    end
    local newList = {}

    for k, v in pairs(self._shieldList) do
        if buffUIdMap[v.buffUniqueId] then
            newList[v.shieldUniqueId] = v
        end
    end
    self._shieldList = newList


    newList = {}
    for k,v in pairs(self._angerList) do
        if buffUIdMap[v.buffUniqueId] then
            newList[v.buffUniqueId] = v
        end
    end

    self._angerList = newList

    newList = {}
    for k, v in ipairs(self._blockList) do
        if buffUIdMap[v.buffUniqueId] then
            table.insert(newList,v)
        end
    end

    self._blockList = newList

end

function LBattleViewUnit:RefreshAllBuffEffect()
    if self._bDeaded then
        self:ShowDeadBuff()
    else
        self:RefreshBuffShow()
    end
    self:ChangeWellOrBadBuffCount()
    self:RefreshFreeze()
    self:RefreshAngerShow()
    self:RefreshBlockShow()
    self:RefreshShieldShow()

    self:RefreshBuffBar()

    self:RefreshShowEffIndex()
end

function LBattleViewUnit:RefreshShowEffIndex()
    local showEffIndex = 1
    local colorState = 1
    local isChangeSpine = false
    --local changeWaitTime = -1
    for k,v in ipairs(self._buffList) do
        local buffRef = GameTable.CombatBuffRef[v.buffId]
        if buffRef then
            if buffRef.specialShow == 1 then
                if not isChangeSpine then
                    if v.round > 0 then
                        isChangeSpine = true
                        if self._showEffIndex == 1 then
                            showEffIndex = 2
                        elseif self._showEffIndex == 2 then
                            showEffIndex = 1
                        end
                    else
                        showEffIndex = 2
                    end
                end
            elseif buffRef.specialShow == 2 then
                colorState = 2
            end
        end
    end

    if self._isChangeSpine then return end

    self._newChangeIndex = showEffIndex
    self._isChangeSpine = isChangeSpine
    local callBackFunc = function()
        if self:IsDead() then return end
        self:ChangeShowEffIndex(showEffIndex)
        self:SetDisplayColor(colorState)
    end
    if isChangeSpine then
        self._changeWaitCb = callBackFunc
    else
        callBackFunc()
    end
end

function LBattleViewUnit:CheckIsHasChangeWaitCb()
    local changeWaitCb = self._changeWaitCb
    self._changeWaitCb = nil
    if changeWaitCb then
        self._isChangeSpine = false
        if self:IsDead() then
            return
        end
        changeWaitCb()
    end
end

function LBattleViewUnit:GetChangeSpineState()
    return self._isChangeSpine
end

function LBattleViewUnit:SetDisplayColor(colorState)
    if self._colorState == colorState then
        return
    end

    self._colorState = colorState


    --local color = colorState == 1 and Color.New(1, 1, 1, 1) or Color.New(0.3,0.3,0.3,1)
    local alpha = colorState == 1 and 1 or 0.3

    if self._spineDp then
        self._spineDp:SetAlpha(alpha)
    end

    if self._spineDp1 then
        self._spineDp1:SetAlpha(alpha)
    end

    if self._spineDp2 then
        self._spineDp2:SetAlpha(alpha)
    end
end

function LBattleViewUnit:InitAllBuffEffect()
    if self._bDeaded then
        self:ShowDeadBuff()
    else
        self:RefreshBuffShow()
    end
    self:ChangeWellOrBadBuffCount()
    self:RefreshAngerShow()
    self:RefreshBlockShow()
    self:RefreshShieldShow()
end

function LBattleViewUnit:RefreshFreeze()

    if self._bDeaded then
        return
    end

    local buffId
    local isFreeze = false
    local dataMgr = self._viewMgr:GetDataMgr()
    for k,v in ipairs(self._buffList) do
        buffId = v.buffId
        isFreeze = dataMgr:IsFreezeBuff(buffId)
        if isFreeze then
            break
        end
    end

    if self._isFreeze == isFreeze then
        return
    end
    self._isFreeze = isFreeze
    self._aniActor:SetFreeze(isFreeze)

    if ENABLE_FIGHT_LOG then
        self._viewMgr:LogMsg(string.format("freeze state %s, buffId %s, heroId: %s",tostring(isFreeze), tostring(buffId), tostring(self.id)))
    end

end

function LBattleViewUnit:RefreshBuffShow()
    if self._bDeaded then return end

    local buffActList = {}

    local showList={}
    local showUniqueMap ={}
    local dataMgr = self._viewMgr:GetDataMgr()
    for k,v in ipairs(self._buffList) do
        local refId = v.buffId
        local isOk = true

        ---@type V_BuffRef
        local buffRefData = GameTable.CombatBuffRef[refId]
        if buffRefData then
            local buffEffShowPos = buffRefData.buffEffShowPos
            if buffEffShowPos == LFightConst.BUFF_POS_SELF or buffEffShowPos == LFightConst.BUFF_POS_OTHER then
                isOk = false
            end
        end

        if isOk then
            local buffEffShowType = dataMgr:GetBuffEffShowTypeById(refId)
            local isDeadShow = dataMgr:IsShowAfterDead(refId) --圣灵buff 不在这里展示

            if not isDeadShow then
                local buff = showList[buffEffShowType] --同类型只显示一个
                if not buff then
                    showList[buffEffShowType] = v
                    showUniqueMap[v.buffUniqueId] = true
                end
            end

            local buffAct = dataMgr:GetBuffAct(refId)
            if buffAct then
                --if LOG_INFO_ENABLED then
                --    print("--------------------------buff act "..refId)
                --end
                local actData = buffActList[refId]
                if not actData then
                    actData =
                    {
                        cnt = 1,
                        buffAct = buffAct
                    }
                    buffActList[refId] = actData
                else
                    actData.cnt = actData.cnt + 1
                end
            end
        end
    end

    local destroyEffMap = {}
    local existMap ={}
    local cnt = #self._curBuffEffectList
    for k= cnt,1,-1 do
        local eff = self._curBuffEffectList[k]
        local uniqueid = eff:GetBuffUniqueId()
        if not showUniqueMap[uniqueid] and not self:IsSpecialBuffEff(uniqueid) then
            destroyEffMap[uniqueid] = true
            eff:Dispose()
            table.remove(self._curBuffEffectList,k)
        else
            existMap[uniqueid] = true
        end
    end

    if self._removeBuff then
        local buffUniqueId = self._removeBuff.buffUniqueId
        if buffUniqueId and buffUniqueId > 0 and not destroyEffMap[buffUniqueId] then
            if self._removeBuff.buffObj then

            end
        end
    end
    self._removeBuff = nil

    for k,v in pairs(showList) do
        if not existMap[v.buffUniqueId] then
            self:CreateBuffEffect(v)
        end
    end

    local material = nil
    for k,v in pairs(showList) do
        local bufRef = GameTable.CombatBuffRef[v.buffId]
        local temp = bufRef.buffMaterial
        if not string.isempty(temp) then
            material = temp
            if self._curMat == material then
                break
            end
        end
    end

    self:SetSpineMat(material)

    self:RefreshBuffAct(buffActList)
end

function LBattleViewUnit:SetSpineMat(mat)
    if self._curMat == mat then
        return
    end

    --Ninfo(string.format("set mat %s",mat))
    self._curMat = mat

    if self._spineDp then
        if mat then
            self._spineDp:SetMat(mat)
        else
            self._spineDp:SetDefaultMat()
        end
    end

    if self._spineDp1 then
        if mat then
            self._spineDp1:SetMat(mat)
        else
            self._spineDp1:SetDefaultMat()
        end
    end

    if self._spineDp2 then
        if mat then
            self._spineDp2:SetMat(mat)
        else
            self._spineDp2:SetDefaultMat()
        end
    end

end

--删除buff光效
function LBattleViewUnit:RemoveBuffEffect(buff)
    if not buff or not self._curBuffEffectList then
        return
    end

    for i, buffEff in ipairs(self._curBuffEffectList) do
        local effBuffUniqueId = buffEff:GetBuffUniqueId()
        if effBuffUniqueId == buff.buffUniqueId then
            buffEff:Dispose()
            table.remove(self._curBuffEffectList,i)
            break
        end
    end
end

---添加buff光效
function LBattleViewUnit:CreateBuffEffect(buff)
    if not buff then
        return
    end
    --if not self._displayObj or not self._displayObj:IsDpValid() then
    --	return
    --end

    local buffRef = GameTable.CombatBuffRef[buff.buffId]
    local effectName = buffRef and buffRef.buffEffShow or ""
    if string.isempty(effectName) then
        return
    end

    --if LOG_INFO_ENABLED then
    --
    --	local str = string.format("heroId %s|buffid %s|buffEffect %s|buffUid %s",self.id,buff.buffId,buff.buffUniqueId,effectName)
    --	printInfoN(str)
    --end


    local dir =  self:GetTeamType() == 2 and LFightConst.DIRECTION_LEFT or LFightConst.DIRECTION_RIGHT

    local data =
    {
        buffId = buff.buffId,
        root = self._unitRootTrans,-- self._displayObj:GetDpTrans(),
        effectName = effectName,
        localPos = self:GetBuffEffShowPos(buff.buffId,self._scale),
        dir = dir,
        order = self:GetRenderOrder(),
        buffUniqueId = buff.buffUniqueId,
        scale = self:GetObjScale(),
    }

    self:AddBattleBuff(data)

end

function LBattleViewUnit:AddBattleBuff(data)
    local buffEff = require("LApp.gameplay.videobattle.view.obj.LBattleViewBuff"):new(self._viewMgr)
    buffEff:ShowEffect(data,self)
    table.insert(self._curBuffEffectList,buffEff)
end

function LBattleViewUnit:IsSpecialBuffEff(uniqueid)
    if not self._specialEffMap then
        self._specialEffMap =
        {
            [LFightConst.BATTLE_EFFECT_BUFF_FAVORABLE] = true,
            [LFightConst.BATTLE_EFFECT_BUFF_HARMFUL] = true,
            [LFightConst.BATTLE_EFFECT_CAN_RELIVE] = true,
        }
    end

    return self._specialEffMap[uniqueid] or false
end

function LBattleViewUnit:GetBuffEffShowPos(buffId,scale)
    local buffEffShowPos = tonumber(self._viewMgr:GetDataMgr():GetBuffEffShowPosById(buffId))
    return self:GetBuffEffShowPosByBuffEffShowPos(buffEffShowPos,scale)
end

function LBattleViewUnit:GetBuffEffShowPosByBuffEffShowPos(buffEffShowPos,scale)
    local offectY = 0.12   -- 头顶偏移值
    local topNodePos = self:GetTopNodeOffset()
    scale = scale or 1
    local topNodePosY = topNodePos.y * scale
    offectY = offectY * scale
    if buffEffShowPos == LFightConst.BUFF_POS_HEAD then
        return Vector3(topNodePos.x,topNodePosY + offectY,0)
    elseif buffEffShowPos == LFightConst.BUFF_POS_BODY then
        local hight = topNodePosY / 2
        return Vector3(topNodePos.x,hight,0)
    elseif buffEffShowPos == LFightConst.BUFF_POS_FOOT then
        return Vector3.zero
    end
end

function LBattleViewUnit:ChangeWellOrBadBuffCount()
    if self._bDeaded then
        return
    end

    local totalWell= 0
    local totalBad = 0

    for k,v in ipairs(self._buffList) do
        local buffRef = GameTable.CombatBuffRef[v.buffId]
        local universalBuffShow = buffRef and buffRef.universalBuffShow --1 增益buff 2 减益buff
        if universalBuffShow == 1 then
            totalWell = totalWell+1
        elseif universalBuffShow == 2 then
            totalBad = totalBad +1
        end
    end

    totalWell = totalWell>4 and 4 or totalWell
    totalBad =  totalBad>4 and 4 or totalBad

    if self._wellBuffCount ~= totalWell then
        self._wellBuffCount = totalWell
        self:UpdateUniversalBuffShowEffect(true)
    end

    if self._badBuffCount ~= totalBad then
        self._badBuffCount = totalBad
        self:UpdateUniversalBuffShowEffect(false)
    end
end

--通用增减益buff表现
function LBattleViewUnit:UpdateUniversalBuffShowEffect(isWell)
    local count = isWell and self._wellBuffCount or self._badBuffCount

    local removeData =
    {
        buffUniqueId = isWell and LFightConst.BATTLE_EFFECT_BUFF_FAVORABLE or LFightConst.BATTLE_EFFECT_BUFF_HARMFUL
    }

    self:RemoveBuffEffect(removeData)

    if count<= 0 then
        return
    end
    local root = self._unitRootTrans -- self._displayObj:GetDpTrans()
    local dir = self:GetTeamType() == 2 and LFightConst.DIRECTION_LEFT or LFightConst.DIRECTION_RIGHT
    local order = self:GetRenderOrder() + 1
    local data = nil
    if isWell then

        data =
        {
            buffUniqueId = LFightConst.BATTLE_EFFECT_BUFF_FAVORABLE,
            root = root,
            dir = dir,
            order = order,
            effectName = "fx_buff_zengyi_" .. count,
        }
    else

        data =
        {
            buffUniqueId = LFightConst.BATTLE_EFFECT_BUFF_HARMFUL,
            root = root,
            dir = dir,
            order = order,
            effectName = "fx_buff_jianyi_" .. count,
        }
    end

    self:AddBattleBuff(data)
end
