function LBattleViewUnit:AddBlockData(blockData)
    table.insert(self._blockList,blockData)
    self:RefreshBlockShow()
end

function LBattleViewUnit:RemoveBlockData(blockData)
    if not blockData then
        return
    end

    local change = false
    for i, v in ipairs(self._blockList) do
        if v.buffUniqueId == blockData.buffUniqueId then
            table.remove(self._blockList,i)
            change = true
            break
        end
    end
    self:RefreshBlockShow()
end

function LBattleViewUnit:UpdateBlockData(hurt)
    local block = self._blockList[1]    -- 优先扣除激活靠前的格挡盾次数
    if block then
        local curCount = block.curCount - 1
        if curCount > 0 then
            block.curCount = curCount
        else
            table.remove(self._blockList,1)
        end
    end

    self:RefreshBlockShow()
end

function LBattleViewUnit:RefreshBlockShow()
    local curCount = 0
    local maxCount = 0
    for k,v in ipairs(self._blockList) do
        curCount = curCount + v.curCount
        maxCount = maxCount + v.maxCount
    end

    self:ShowBlockShield(curCount,maxCount)
end

