function LBattleViewUnit:AddShieldData(shieldData)
    self._shieldList[shieldData.shieldUniqueId] = shieldData

    self:RefreshShieldShow()
end

function LBattleViewUnit:RemoveShieldData(shield)
    if not shield then
        return
    end

    for i, v in pairs(self._shieldList) do
        if v.buffUniqueId == shield.buffUniqueId then
            self._shieldList[v.shieldUniqueId] = nil
            break
        end
    end

    self:RefreshShieldShow()
end

--function LBattleViewUnit:GetShieldDataByUniqueId(shieldUniqueId)
--	return self._shieldList[shieldUniqueId]
--end

function LBattleViewUnit:UpdateShieldData(shieldData)
    local shield = self._shieldList[shieldData.shieldUniqueId]
    if shield then
        local curHP = shield.curHP + shieldData.hurt
        if curHP<=0 then
            self._shieldList[shieldData.shieldUniqueId] = nil
        else
            shield.curHP = curHP
        end
    end

    self:RefreshShieldShow()
end

function LBattleViewUnit:RefreshShieldShow()
    local curShieldV = 0
    local maxShieldV = 0

    for k,v in pairs(self._shieldList) do
        curShieldV = curShieldV + v.curHP
        maxShieldV = maxShieldV + v.maxHP
    end

    self:ShowNormalShield(curShieldV,maxShieldV)
end

---@param effect LBattleBaseEffectData
function LBattleViewUnit:UpdateBuffData(effect)
    local buffEffectData = effect.buffEffect
    for k, v in ipairs(self._buffList) do
        if v.buffUniqueId == buffEffectData.buffUniqueId then
            v.round = buffEffectData.round
            break
        end
    end
end

--- 判断是否有buff需要再受击时显示
function LBattleViewUnit:CheckHasHitBuffEffShow(ht)
    if not self._buffList or #self._buffList < 1 then return false end
    local buffId
    local dataMgr = self._viewMgr:GetDataMgr()
    for i,v in ipairs(self._buffList) do
        buffId = v.buffId
        if buffId and buffId > 0 then
            ---@type V_BuffRef
            local buffRef = GameTable.CombatBuffRef[buffId]
            if buffRef and buffRef.buffEffShowTime == 2 and not string.isempty(buffRef.buffEffShow) then
                if dataMgr:CheckNeedShowDamageBuffEff(buffId,ht) then
                    return true,buffRef
                end
            end
        end
    end
    return false
end
