function LBattleViewUnit:OnUpdateBuffRound(nowRound)
    for i, buff in ipairs(self._buffList) do
        local surplusRound = nowRound - buff.startRound
        if surplusRound < 0 then surplusRound = 0 end
        buff.currentRound = buff.round - surplusRound
    end

    if not self.unitData then
        return
    end
    self.unitData:OnUpdateBuffRound(nowRound)

    FireEvent(EventNames.BUFF_DETAILS_UPDATE,self.unitData)
end
