---出生
function LBattleViewUnit:ShowBirth(func)

    if not self:IsOnGridObj() then
        local endFunc = self._birthFunc
        self._birthFunc = nil
        if endFunc then
            endFunc()
        end
        return
    end

    local viewMgr = self._viewMgr
    --- 2024/7/15： 目前出生动画由该战斗类型所设定的速度做
    local birthSpeed = viewMgr:GetSpeed()
