function LBattleViewUnit:KillBirthTween()
    if self._seqCom then
        self._seqCom:DeleteSeq("birthTween")

    end
end

function LBattleViewUnit:LoadBirthEff()
    local showEffRef = self:GetShowEffRef()
    if not showEffRef then
        return
    end
    local decoCtrl = self._viewMgr:GetDecoCtrl()

    local resName = showEffRef.startEffect
    if string.isempty(resName) then
        return
    end

    local key = string.format("%s_birthEffect",self.id)
    self._waitLoadMap = self._waitLoadMap or {}
    self._waitLoadMap[key] = true

    local effectData =
    {
        effectKey = key,
        loadedCall = function(effect)
            if self._waitLoadMap then
                self._waitLoadMap[key] = nil
            end
            local tran = effect:GetDpTrans()
            ShowObject(tran,false)
            self:CheckLoadEnd()
        end,
        failCallback = function()
            if self._waitLoadMap then
                self._waitLoadMap[key] = nil
            end
            self:CheckLoadEnd()
        end,
        root = self._unitRootTrans,
        resName = resName,
    }
    decoCtrl:CreateEffect(effectData)

end

function LBattleViewUnit:CheckLoadEnd()
    if self._waitLoadMap then
        for k,v in pairs(self._waitLoadMap) do
            if v then
                return
            end
        end
    end

    if self._loadCnt > 0 then
        return
    end

    self:OnBattleObjLoaded()

end

function LBattleViewUnit:ShowBirthEffect()
    local decoCtrl = self._viewMgr:GetDecoCtrl()
    local effectKey = string.format("%s_birthEffect",self.id)
    local info = decoCtrl:FindEffectInfoByKey(effectKey)
    if not info then
        return
    end
    local effect = info.effect
    effect:RestartFx()
end

function LBattleViewUnit:ClearBirthEffect()
    local decoCtrl = self._viewMgr:GetDecoCtrl()
    local effectKey = string.format("%s_birthEffect",self.id)
    decoCtrl:DeleteEffect(effectKey)
end

