function LBattleViewUnit:SetDead(bDead)
    self._bDeaded = bDead
    self._deadActionEnd = bDead
    if bDead then
        self._state = BattleUnitState.Dead
    else
        self._state = BattleUnitState.Idle
    end
end
---死亡
function LBattleViewUnit:DoDead(time,force,canRelive,delayTime)
    if self._isDisposed then return end

    if not force then

        local needWait = false
        local actDeadTime = time
        if delayTime and delayTime >0 then
            actDeadTime = time + delayTime
            needWait = true
        end

        if self:HasWaitDeadState() then
            needWait = true
        end

        if not self:IsReliveEnd() then
            needWait = true
            actDeadTime = actDeadTime+ self._reliveInterval
        end
        if needWait then
            self:AddDeadShow({isDead = true,curTime = actDeadTime,canRelive = canRelive})
            return
        end

    end

    if self._bDeaded then return end

    self._viewMgr:ClearHurtCntList()
    self:ClearBloodList()

    self._aniActor:SetFreeze(false) --解除冰冻效果

    self._bDeaded = true
    self._state = BattleUnitState.Dead
    self._bDeadEnd = false

    self._deadActionEnd = false
    self:StopMove()

    local showEffRef = self:GetShowEffRef()
    local deadTime = LxDataHelper.GetSpineAniTime(showEffRef.prefabName, LSpineAniConst.die, 0.2)
    self:PlayAni(LSpineAniConst.die)
    self:PlayDieSound()

    self:KillBirthTween()
    self:KillDeadTween()

    self._isDeading = true
    local tweenSeq = self._seqCom:CreateSeq("deadTween")

    local showtime = 0.1

    local alphaFunc = function (value)
        self:SetObjAlpha(value)
    end

    tweenSeq:AppendInterval(deadTime)
    local alphaTween = LxUiHelper.TweenFloat(1,0.5,showtime,alphaFunc):SetEase(DG.Tweening.Ease.InSine)
    local alphaTween1 = LxUiHelper.TweenFloat(0.5,1,showtime,alphaFunc):SetEase(DG.Tweening.Ease.OutSine)
    local alphaTween2 = LxUiHelper.TweenFloat(1,0,showtime,alphaFunc):SetEase(DG.Tweening.Ease.InSine)
    tweenSeq:Append(alphaTween)
    tweenSeq:Append(alphaTween1)
    tweenSeq:Append(alphaTween2)

    tweenSeq:AppendCallback(function ()
        local side = self:GetTeamIdx()
        self._viewMgr:UpdateCanReliveEff(side)
    end)

    tweenSeq:InsertCallback(deadTime,function ()
        --self:ShowBloodStick(false)
        self:SetHideBloodKey("dead")
        self:SetHasBuffEffectStatus(false)
        self:DestroyAllBuff()
        self:ShowDeadBuff()
        self._deadActionEnd = true
        --self._isDeading = false

        self._changeWaitCb = nil
        self._isChangeSpine = false
    end)

    tweenSeq:OnComplete(function()
        self._bDeadEnd = true
        self._isDeading = false
        self:SetPosition(self._gridPos)

    end)
    tweenSeq:OnKill(function ()
        self._isDeading = false
        self._deadActionEnd = true
        self._bDeadEnd = true
    end)

    tweenSeq:PlayForward()

    FireEvent(EventNames.BATTLE_HERO_LIVE_CHANGE,self.id,true)
end


function LBattleViewUnit:UpdateCanReliveEff()
    if self._battleObjType ~= LFightConst.OBJ_NORMAL then
        return
    end

    local isShow = self._canRelive
    self:RemoveBuffEffect({buffUniqueId = LFightConst.BATTLE_EFFECT_CAN_RELIVE})
    if not isShow then
        return
    end

    if not self:IsDead() then
        return
    end

    --if not self._displayObj then
    --	return
    --end

    local data =
    {
        root = self._unitRootTrans, --self._displayObj:GetDpTrans(),
        effectName = "fx_fuhuobiaoji",
        dir =  self:GetTeamType() == 2 and LFightConst.DIRECTION_LEFT or LFightConst.DIRECTION_RIGHT,
        order = self:GetRenderOrder() + 1,
        buffUniqueId = LFightConst.BATTLE_EFFECT_CAN_RELIVE,
    }

    self:AddBattleBuff(data)
end

function LBattleViewUnit:ShowCanReliveEff(isShow)
    self._canRelive = isShow
    self:UpdateCanReliveEff()
end
function LBattleViewUnit:DestroyAllBuff()
    if self._curBuffEffectList then
        for i, v in ipairs(self._curBuffEffectList) do
            v:Dispose()
        end
    end
    self._curBuffEffectList = {}
end

---圣灵，驱灵死亡时表现
function LBattleViewUnit:ShowDeadBuff()

    local showList={}
    local buffIdMap= {}
    local dataMgr = self._viewMgr:GetDataMgr()
    for k,v in ipairs(self._buffList) do
        local buffEffShowType = dataMgr:GetBuffEffShowTypeById(v.buffId)
        local isDeadShow = dataMgr:IsShowAfterDead(v.buffId)
        if isDeadShow then
            local buff = showList[buffEffShowType] --同类型只显示一个
            if not buff then
                showList[buffEffShowType] = v
                buffIdMap[v.buffId] = true
            end
        end
    end

    local rejectMap = {}
    for k,v in pairs(showList) do
        local buffId = v.buffId
        local statelist = dataMgr:GetBuffStateIDByBuffID(buffId)
        for k1,v1 in ipairs(statelist) do
            if v1 == LBuffStateConst.BUFF_STATE_SHENGLING then
                local qulingId = dataMgr:GetQulingId(buffId)
                local exist = buffIdMap[qulingId] --存在驱灵则排除圣灵
                if exist then
                    rejectMap[buffId] = true
                end
                break
            end
        end
    end

    local finalList = {}
    local showUniqueMap ={}
    for k,v in pairs(showList) do
        local buffId = v.buffId
        if not rejectMap[buffId] then
            table.insert(finalList,v)
            showUniqueMap[v.buffUniqueId] = true
        end
    end

    local existMap ={}
    local cnt = #self._curBuffEffectList
    for k= cnt,1,-1 do
        local eff = self._curBuffEffectList[k]
        local uniqueid = eff:GetBuffUniqueId()
        if not showUniqueMap[uniqueid] and not self:IsSpecialBuffEff(uniqueid) then
            eff:Dispose()
            table.remove(self._curBuffEffectList,k)
        else
            existMap[uniqueid] = true
        end
    end
    for k,v in ipairs(finalList) do
        if not existMap[v.buffUniqueId] then
            self:CreateBuffEffect(v)
        end
    end

end

-----------------------------------------------------------------
function LBattleViewUnit:DoRelive(time,force,reliveSkill)
    if self._isDisposed then return end

    if not force then
        if not self._bDeadEnd or self:HasWaitDeadState() then
            local delayTime = time+ self:GetDeadInterval()
            self:AddDeadShow({isDead = false,curTime = delayTime})
            return
        end
    end

    if not self._bDeaded then
        return
    end

    self:KillDeadTween()

    self._bDeaded = false
    self._state = BattleUnitState.Idle
    self._bDeadEnd = false

    local isSkillCtrl = reliveSkill or self._isSkillPlaying
    if isSkillCtrl then
        self:SetObjAlpha(1)
    else
        if self._spineDp then
            self._spineDp:ResetSpine()
            self._spineDp:SetAlpha(1)
        end
        if self._spineDp1 then
            self._spineDp1:ResetSpine()
            self._spineDp1:SetAlpha(1)
        end
        if self._spineDp2 then
            self._spineDp2:ResetSpine()
            self._spineDp2:SetAlpha(1)
        end
        self:PlayIdleAni()
    end



    self:ReleaseHideKey("dead")

    self:RefreshAllBuffEffect()

    self:ShowCanReliveEff(false)

    self._isReliving = true
    local seq = self._seqCom:CreateSeq("reliveTween")
    seq:AppendInterval(self._reliveInterval)
    seq:OnKill(function ()
        self._isReliving = false
    end)
    seq:OnComplete(function ()
        --self:SetHasBuffEffectStatus(true)
        self._isReliving = false
    end)
    seq:PlayForward()


    FireEvent(EventNames.BATTLE_HERO_LIVE_CHANGE,self.id,false)

end

function LBattleViewUnit:IsReliveEnd()
    return not self._isReliving
end

function LBattleViewUnit:HasWaitDeadState()
    if self._deadList and #self._deadList>0 then
        return true
    end
    return false
end

function LBattleViewUnit:IsInDeadAction()
    if self._battleObjType ~= LFightConst.OBJ_NORMAL then
        return false
    end

    if self:HasWaitDeadState() then
        return true
    end

    if self._isReliving then
        return true
    end

    if self._isDeading then
        return true
    end

    return false
end

--[[
data =
{
isDead,
curTime,
noAct,
}
]]
function LBattleViewUnit:AddDeadShow(lifeInfo)
    if not self._deadList then
        self._deadList={}
    end
    local data = {
        isDead =  lifeInfo.isDead,
        canRelive = lifeInfo.canRelive,
    }
    if #self._deadList == 0 then
        data.showTime = lifeInfo.curTime
    else
        local last = self._deadList[#self._deadList]
        if last.isDead then
            data.showTime = last.showTime + self:GetDeadInterval()
        else
            data.showTime = last.showTime + self._reliveInterval
        end

    end

    table.insert(self._deadList,data)

    self._updateDeadState = true
end

function LBattleViewUnit:UpdateDeadState(time)
    if not self._updateDeadState then
        return
    end
    if not self._deadList then
        self._updateDeadState = false
        return
    end

    if #self._deadList ==0 then
        self._updateDeadState = false
        return
    end
    local index = nil
    for k,v in ipairs(self._deadList) do
        if v.showTime<=time then
            if v.isDead then
                self:DoDead(time,true,v.canRelive)
            else
                self:DoRelive(time,true)
            end
            index = k
            break
        end
    end
    if index then
        table.remove(self._deadList,index)
    end
end
