function LBattleViewUnit:StartFade(time)

    local tweenSeq = self._seqCom:CreateSeq("alphaSeq")
    local alphaFunc = function(value)
        self:SetObjAlpha(value)
    end
    local alphaTween = LxUiHelper.TweenFloat(1,0,time,alphaFunc):SetEase(DG.Tweening.Ease.InSine)
    tweenSeq:Append(alphaTween)
    tweenSeq:PlayForward()
end

function LBattleViewUnit:StartInSitu(effData)
    local playTime = effData.playTime
    local dissipateTime = effData.dissipateTime
    local doFade = dissipateTime and dissipateTime > 0
    local tweenSeq = self._seqCom:CreateSeq("startInSitu")
    if doFade then
        local alphaFunc = function(value)
            self:SetObjAlpha(value)
        end
        local alphaHideTween = LxUiHelper.TweenFloat(1,0,dissipateTime,alphaFunc):SetEase(DG.Tweening.Ease.InSine)
        tweenSeq:Append(alphaHideTween)
        local showTime = playTime - dissipateTime
        tweenSeq:Insert(showTime,
                LxUiHelper.TweenFloat(0,1,dissipateTime,alphaFunc):SetEase(DG.Tweening.Ease.InSine))
    else
        self:SetObjAlpha(0)
        tweenSeq:AppendInterval(playTime)
        tweenSeq:AppendCallback(function()
            self:SetObjAlpha(1)
        end)
    end
    tweenSeq:PlayForward()
end

function LBattleViewUnit:SetObjAlpha(value)
    --print("set alpha "..value)
    if self._spineDp then
        self._spineDp:SetAlpha(value)
    end

    if self._spineDp1 then
        self._spineDp1:SetAlpha(value)
    end

    if self._spineDp2 then
        self._spineDp2:SetAlpha(value)
    end


    for k, v in ipairs(self._displayObjEffList) do
        v:SetVisible(value > 0)
    end
end

function LBattleViewUnit:SetHasBuffEffectStatus(bShow)
    if not self._viewMgr then return end
    if self._viewMgr:IsDisposed() then return end
    self._viewMgr:ResetBuffEffect(self:GetId(),bShow)
end

