    if isShow and self:IsDead() then
        isShow = false
    end
    local alpha = isShow and 1 or 0
    self:SetObjAlpha(alpha)
    --if self._bloodStick then
    --    self._bloodStick:SetVisible(isShow)
    --end
    self:ShowBloodStick(isShow)
end

