---@param effect LBattlePositionEffectData
function LBattleViewUnit:ChangeIndex(effect,duration)

    local oldIndex = effect.oldIndex
    local newIndex = effect.newIndex

    --printInfoN(string.format("changeIndex id %s,cur %s,newI %s, oldI %s",self.id,self.index,newIndex,oldIndex))

    if self.index == oldIndex then
        self:ChangeIndexPass(effect,duration)
        return
    elseif self.index == newIndex then
        self.index = oldIndex
    else
        return
    end

    local order = self:GetRenderOrder()
    self:SetRenderOrder(order)

    local gridPos = self._viewMgr:GetGridPosByIndex(self.teamIdx,self.index)

    self._gridPos = gridPos

    self:StartMove(gridPos,duration)
end

---@param effect LBattlePositionEffectData
function LBattleViewUnit:ChangeIndexPass(effect,duration)
    self.index = effect.newIndex


    local passPosList = {}
    local passList = effect.wayIndexList or {}
    for k,v in ipairs(passList) do
        local gridPos = self._viewMgr:GetGridPosByIndex(self.teamIdx,v)
        table.insert(passPosList,gridPos)
    end

    local gridPos = self._viewMgr:GetGridPosByIndex(self.teamIdx,self.index)
    table.insert(passPosList,gridPos)

    self._gridPos = gridPos

    passPosList = self:ModifyMoveOffset(passPosList)
    local time =  duration/#passPosList
    for k,v in ipairs(passPosList) do
        self:InsertMovePara(v,time)
    end


end

function LBattleViewUnit:OnMoveUpdate()
    if not self._moveParaList then
        return
    end

    if self._moveActor:IsMoving() then
        return
    end

    local para = table.remove(self._moveParaList,1)
    if not para then
        self._moveParaList = nil
        return
    end

    self:StartMove(para.pos,para.time)

end

function LBattleViewUnit:ModifyMoveOffset(posList)
    local cnt = #posList
    if cnt >= 2 then
        local newList = {}
        newList[1] = posList[1]
        for k=2,cnt do
            local lastPos = posList[k-1]
            local curPos = posList[k]
            local newPos = Vector3.Lerp(lastPos,curPos,0.9)
            newList[k] = newPos
        end

        return newList
    end

    return posList
end


function LBattleViewUnit:SetSkillPlaying(isPlaying)
    self._isSkillPlaying = isPlaying
    if isPlaying then
        self:SetObjAlpha(1)
    end
end

function LBattleViewUnit:RefreshBuffAct(curList)
    if not self._curBuffActList then
        self._curBuffActList = {}
    end

    local dpTrans = self._unitRootTrans -- self._displayObj:GetDpTrans()
    if not IsValid(dpTrans) then
        return
    end

    local isLeft = self:GetTeamType() == BattleTeamSide.teamB

    local removeList = {}
    for k,v in pairs(self._curBuffActList) do
        if not curList[k] then
            table.insert(removeList,{ buffId= k})
        end
    end


    local renderOrder = self:GetRenderOrder()

    local refreshList = {}
    for k,v in  pairs(curList) do
        local resName = v.buffAct.spineName
        local aniName = nil
        local lastAni = nil

        if LOG_INFO_ENABLED then
            print(string.format("buff id %s ,cnt %s",k,v.cnt))
        end

        for k1,v1 in ipairs(v.buffAct.aniList) do
            lastAni = v1.ani
            if v.cnt <= v1.cnt then
                aniName = v1.ani
                break
            end
        end

        if aniName == nil then
            aniName = lastAni
        end

        local data =
        {
            trans = dpTrans,
            resName = resName,
            sorting = renderOrder,
            key = k,
            isLeft = isLeft,
            endFunc = function(spine)
                spine:PlayAnimation(0,aniName,true,false,0)
            end
        }

        table.insert(refreshList,data)
    end

    self:ShowBuffAct(refreshList,removeList)

    self._curBuffActList = curList
end

function LBattleViewUnit:ShowBuffAct(refreshList,removeList)


    for k,v in pairs(refreshList) do
        self._buffSpineQueue:MakeObject(v)
    end

    for k,v in pairs(removeList) do
        self._buffSpineQueue:DestroyByKey(v.buffId)
    end
end

function LBattleViewUnit:RefreshBuffActLayer(order)
    local renderOrder = order or self:GetRenderOrder()
    local renderLayer = self:GetRenderLayer()
    self._buffSpineQueue:RefreshAllRenderLayer(renderLayer,renderOrder + 1)
end

function LBattleViewUnit:RefreshBuffBar()
    local list = {}
    local dataMgr = self._viewMgr:GetDataMgr()
    for k,v in ipairs(self._buffList) do
        local buffUIPara = dataMgr:GetBuffBuffUi(v.buffId)
        if buffUIPara then
            local data = list[v.buffId]
            if not data then
                data = {}
                list[v.buffId] = data
                data.buffUIPara = buffUIPara
                data.cnt = 0
            end
            data.cnt = data.cnt + 1
        end
    end


    self:RefreshBuffBarShow(list)
end

function LBattleViewUnit:PlayAni_Actor(ani,loop,mixTime)
    for k,v in ipairs(self._displayObjList) do
        v:SetAnimationTimeScale(1)
        v:PlayAnimation(0,ani,loop,false,mixTime)
    end
end

function LBattleViewUnit:SetAniTimeScale_Actor(timeScale)
    for k,v in ipairs(self._displayObjList) do
        v:SetAnimationTimeScale(timeScale)
    end
end

