function LBattleViewUnit:SetHideBloodKey(key)
    if not self._hideBloodKey then
        self._hideBloodKey= {}
    end

    self._hideBloodKey[key] = true

    self:CheckShowBlood()
end

function LBattleViewUnit:ReleaseHideKey(key)
    if self._hideBloodKey then
        self._hideBloodKey[key] = nil
    end

    self:CheckShowBlood()
end

function LBattleViewUnit:CheckShowBlood()
    local showBlood = true
    if not table.isempty(self._hideBloodKey) then
        showBlood = false
    end

    local isHide = self:IsSummonHideBlood()
    if isHide then
        showBlood = false
    end


    self:ShowBloodStick(showBlood)
end

function LBattleViewUnit:ShowSummonBirth()
    self._isSummonReady = false

    self:SetPosByGrid()
    self:SetObjAlpha(0)
    local seq = self._seqCom:CreateSeq("summonBirth")
    if self._battleObjType == LFightConst.OBJ_PET then
        seq:AppendCallback(function ()
            self:ShowBirthEffect()
        end)
        seq:AppendInterval(3)
    else
        seq:AppendInterval(1)
    end

    local alphaFunc = function (value)
        self:SetObjAlpha(value)
    end
    local alphaTween = LxUiHelper.TweenFloat(0,1,1,alphaFunc):SetEase(DG.Tweening.Ease.InSine)
    seq:Join(alphaTween)
    seq:OnComplete(function ()
        self._isSummonReady = true
        self:CheckShowBlood()
        self:ClearBirthEffect()
    end)
    seq:PlayForward()

end

function LBattleViewUnit:IsSummonHeroReady()
    return self._isSummonReady
end

function LBattleViewUnit:IsObjReady()
    if self._summonAndPet[self._battleObjType] then
        return self:IsSummonHeroReady()
    else
        return true
    end
end

function LBattleViewUnit:IsSummonHideBlood()
    if not self._summonAndPet[self._battleObjType]  then
        return
    end

    if table.isempty(self._buffList) then
        return
    end

    local dataMgr = self._viewMgr:GetDataMgr()
    for k,v in pairs(self._buffList) do
        local statelist = dataMgr:GetBuffStateIDByBuffID(v.buffId)
        for k1,v1 in ipairs(statelist) do
            if v1 == LBuffStateConst.BUFF_STATE_SUMMON_UNSELECT then
                return true
            end
        end
    end
end

function LBattleViewUnit:UpdateCdRound(roundCd)

    self._roundCd = roundCd

    if not self._bloodStick then
        return
    end

    self._bloodStick:ShowCdInfo(roundCd)
end


function LBattleViewUnit:GetPlaySoundBattle(soundBattle,effData)
    if not self:IsOnGridObj() then return soundBattle end

    if not self.unitData then return soundBattle end

    return self.unitData:GetPlaySoundBattle(soundBattle,effData)
end

function LBattleViewUnit:GetObjScale()
    return self._scale
end

-----------------------------------------------------------------
function LBattleViewUnit:Dispose()
    if self._isDisposed then return end

    self:ClearAllTween()

    self:KillBirthTween()
    self:KillDeadTween()

    if self._bloodStick then
        self._bloodStick:Dispose()
        self._bloodStick = nil
    end

    if self._bubbleStick then
        self._bubbleStick:DestroyBubble()
        self._bubbleStick = nil
    end

    for k,v in ipairs(self._displayObjEffList) do
        v:Dispose()
    end
    self._displayObjEffList = nil



    self:ClearCardEff()
    if IsValid(self._unitRootGo) then
        LxResUtil.DestroyObject(self._unitRootGo)
    end
    self._unitRootTrans = nil
    if IsValid(self._heroBgTrans) then
        LxResUtil.DestroyObject(self._heroBgTrans.gameObject)
    end
    self._heroBgTrans = nil




    self:DestroyAllBuff()

    if self._objHud then
        self._objHud:Dispose()
        self._objHud = nil
    end

    if self._spineDp then
        self._spineDp:Dispose()
        self._spineDp = nil
    end

    if self._spineDp1 then
        self._spineDp1:Dispose()
        self._spineDp1 = nil
    end
    if self._spineDp2 then
        self._spineDp2:Dispose()
        self._spineDp2 = nil
    end

    if self._seqCom then
        self._seqCom:Dispose()
        self._seqCom= nil
    end

    LxNodeBase.Dispose(self)

    self._isDisposed = true
end

function LBattleViewUnit:OnUpdate(time, deltaTime)
    if self._aniActor then
        self._aniActor:OnUpdate(time, deltaTime)
    end
    if self._moveActor then
        self._moveActor:OnUpdate(time, deltaTime)
    end

    self:UpdateBloodInternal(time)
    self:UpdateDeadState(time)
    self:OnMoveUpdate()
end

------------------------------------------------------------------
return LBattleViewUnit